/**
 * Logo Carousel Script
 * Converts a grid of logos into a horizontally scrolling carousel
 * with automatic scroll and mouse interaction
 */

(function($) {
    'use strict';
    
    // Configuration
    const config = {
        scrollSpeed: 1,           // pixels per frame for auto-scroll
        scrollInterval: 30,       // milliseconds between scroll frames
        mouseWheelMultiplier: 2,  // speed multiplier for mouse wheel
        dragMultiplier: 1.5       // speed multiplier for mouse drag
    };
    
    // Initialize when DOM is ready
    $(document).ready(function() {
        //initLogoCarousel();
    });
    
    function initLogoCarousel() {
        // Target the parent container
        const $container = $('.vc_row.wpb_row.vc_inner.vc_row-fluid.vc_custom_1561476596944');
        
        if ($container.length === 0) {
            console.warn('Logo carousel container not found');
            return;
        }
        
        // Restructure the HTML
        const $columns = $container.find('.wpb_column');
        const $logos = $container.find('.wpb_single_image');
        
        // Create carousel wrapper
        const $carouselWrapper = $('<div>', {
            class: 'logo-carousel-wrapper',
            css: {
                width: '100%',
                overflow: 'hidden',
                position: 'relative'
            }
        });
        
        // Create scrolling track
        const $scrollTrack = $('<div>', {
            class: 'logo-carousel-track',
            css: {
                display: 'flex',
                alignItems: 'center',
                gap: '40px',
                width: 'fit-content',
                padding: '20px 0'
            }
        });
        
        // Clone logos and add to track (duplicate for seamless loop)
        $logos.each(function() {
            const $logoClone = $(this).clone();
            $logoClone.css({
                flex: '0 0 auto',
                width: '200px',
                margin: '0'
            });
            $scrollTrack.append($logoClone);
        });
        
        // Duplicate the logos for seamless infinite scroll
        $logos.each(function() {
            const $logoClone = $(this).clone();
            $logoClone.css({
                flex: '0 0 auto',
                width: '200px',
                margin: '0'
            });
            $scrollTrack.append($logoClone);
        });
        
        // Assemble carousel
        $carouselWrapper.append($scrollTrack);
        $container.empty().append($carouselWrapper);
        
        // Scroll behavior variables
        let scrollPosition = 0;
        let isScrolling = true;
        let isDragging = false;
        let startX = 0;
        let scrollLeft = 0;
        let autoScrollTimer = null;
        
        // Get track width for seamless loop
        const trackWidth = $scrollTrack[0].scrollWidth / 2;
        
        // Auto-scroll function
        function autoScroll() {
            if (isScrolling && !isDragging) {
                scrollPosition += config.scrollSpeed;
                
                // Reset position for seamless loop
                if (scrollPosition >= trackWidth) {
                    scrollPosition = 0;
                }
                
                $scrollTrack.css('transform', `translateX(-${scrollPosition}px)`);
            }
        }
        
        // Start auto-scroll
        autoScrollTimer = setInterval(autoScroll, config.scrollInterval);
        
        // Mouse wheel control
        $carouselWrapper.on('wheel', function(e) {
            e.preventDefault();
            
            // Pause auto-scroll temporarily
            isScrolling = false;
            clearTimeout($carouselWrapper.data('scrollTimeout'));
            
            // Manual scroll
            scrollPosition += e.originalEvent.deltaY * config.mouseWheelMultiplier;
            
            // Keep within bounds
            if (scrollPosition < 0) scrollPosition = trackWidth + scrollPosition;
            if (scrollPosition >= trackWidth) scrollPosition = scrollPosition - trackWidth;
            
            $scrollTrack.css('transform', `translateX(-${scrollPosition}px)`);
            
            // Resume auto-scroll after 2 seconds of inactivity
            const timeout = setTimeout(function() {
                isScrolling = true;
            }, 2000);
            $carouselWrapper.data('scrollTimeout', timeout);
        });
        
        // Mouse drag control
        $carouselWrapper.on('mousedown', function(e) {
            isDragging = true;
            isScrolling = false;
            startX = e.pageX;
            scrollLeft = scrollPosition;
            $carouselWrapper.css('cursor', 'grabbing');
        });
        
        $(document).on('mousemove', function(e) {
            if (!isDragging) return;
            e.preventDefault();
            
            const x = e.pageX;
            const walk = (startX - x) * config.dragMultiplier;
            scrollPosition = scrollLeft + walk;
            
            // Keep within bounds
            if (scrollPosition < 0) scrollPosition = trackWidth + scrollPosition;
            if (scrollPosition >= trackWidth) scrollPosition = scrollPosition - trackWidth;
            
            $scrollTrack.css('transform', `translateX(-${scrollPosition}px)`);
        });
        
        $(document).on('mouseup', function() {
            if (isDragging) {
                isDragging = false;
                $carouselWrapper.css('cursor', 'grab');
                
                // Resume auto-scroll after 2 seconds
                clearTimeout($carouselWrapper.data('scrollTimeout'));
                const timeout = setTimeout(function() {
                    isScrolling = true;
                }, 2000);
                $carouselWrapper.data('scrollTimeout', timeout);
            }
        });
        
        // Set cursor style
        $carouselWrapper.css('cursor', 'grab');
        
        // Pause on hover (optional)
        $carouselWrapper.hover(
            function() {
                isScrolling = false;
            },
            function() {
                isScrolling = true;
            }
        );
    }
    
})(jQuery);